static bool ContainsNumbers(ETSChecker *checker, Type *tp)
{
    auto isSubtypeOfNumeric = [checker](Type *tp2) {
        return checker->Relation()->IsSupertypeOf(checker->GetGlobalTypesHolder()->GlobalNumericBuiltinType(), tp2);
